CREATE TRIGGER [dbo].[OrderItemUnit_History]ON [dbo].[OrderItemUnit]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.OrderItemUnitId IS NOT NULL AND d.OrderItemUnitId IS NULL THEN 'I' 		WHEN i.OrderItemUnitId IS NOT NULL AND d.OrderItemUnitId IS NOT NULL THEN 'U' 		WHEN i.OrderItemUnitId IS NULL AND d.OrderItemUnitId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.OrderItemUnitId = d.OrderItemUnitId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_OrderItemUnit([OrderItemUnitId], [OrderItemId], [PartId], [SerialNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemUnitId], [OrderItemId], [PartId], [SerialNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_OrderItemUnit([OrderItemUnitId], [OrderItemId], [PartId], [SerialNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemUnitId], [OrderItemId], [PartId], [SerialNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND